const posts = $('📅 Leer Calendario Semanal').item.json;
const prompts = $input.all().map(item => item.json);

// Filtrar prompts especificos
const hookPrompt = prompts.find(p => p.id === 'PRM-HOOK-01')?.prompt_text || '';
const copyPrompt = prompts.find(p => p.id === 'PRM-COPY-01')?.prompt_text || '';
const qaPrompt = prompts.find(p => p.id === 'PRM-QA-01')?.prompt_text || '';

return posts.map(post => ({
  json: {
    ...post,
    prompt_hook: hookPrompt,
    prompt_copy: copyPrompt,
    prompt_qa: qaPrompt
  }
}));

try {
  let hooksObj = $input.first().json;
  if (hooksObj.text) {
    const cleanText = hooksObj.text.replace(/```json/g, '').replace(/```/g, '').trim();
    hooksObj = JSON.parse(cleanText);
  }
  return {
    json: {
      ...$input.first().json,
      hook_principal: hooksObj.hook_principal || hooksObj.hook_seleccionado,
      hook_alt_1: hooksObj.hook_alt_1,
      hook_alt_2: hooksObj.hook_alt_2
    }
  };
} catch (e) {
  return {
    json: {
      ...$input.first().json,
      hook_principal: '¿Sabías que tu negocio puede pagar menos impuestos legalmente?',
      error: 'Error parseando hooks'
    }
  };
}

