try {
  let qaObj = $input.first().json;
  if (qaObj.text) {
    const cleanText = qaObj.text.replace(/```json/g, '').replace(/```/g, '').trim();
    qaObj = JSON.parse(cleanText);
  }

  let finalCopy = $input.first().json.copy_body;
  if (qaObj.es_humano === false && qaObj.version_reescrita) {
    finalCopy = qaObj.version_reescrita;
  }

  return {
    json: {
      ...$input.first().json,
      copy_body: finalCopy,
      qa_humanizacion: true,
      score_humanizacion: qaObj.score_humanizacion || 8,
      es_humano: qaObj.es_humano
    }
  };
} catch (e) {
  return {
    json: {
      ...$input.first().json,
      qa_humanizacion: true,
      es_humano: true
    }
  };
}

const items = $input.all().map(item => item.json);

let html = `
<h2>📝 Contexia Content OS — Borradores Generados para Revisión</h2>
<p>Hola Juan Esteban. Aquí tienes las piezas de la semana listas y pasadas por el filtro de humanización de Taty Contadora:</p>
<table border="1" cellpadding="10" style="border-collapse: collapse; width: 100%; border-color: #e2e8f0;">
  <tr style="background-color: #0f172a; color: white;">
    <th>Tema</th>
    <th>Formato</th>
    <th>Hook</th>
    <th>Copy</th>
    <th>CTA</th>
  </tr>
`;

items.forEach(item => {
  html += `
  <tr>
    <td><strong>${item.titulo_trabajo || 'Idea'}</strong></td>
    <td><span style="background-color: #2dd4bf; color: #0f172a; padding: 2px 6px; border-radius: 4px; font-size: 12px;">${item.formato || 'TEXTO'}</span></td>
    <td>${item.hook_principal}</td>
    <td>${item.copy_body.replace(/\n/g, '<br>')}</td>
    <td><em>${item.cta}</em></td>
  </tr>
  `;
});

html += `
</table>
<br>
<p><strong>💡 Próximo paso:</strong> Ve a tu base de datos o portal, edita si es necesario y cambia el estado a <strong>APPROVED</strong> para programar.</p>
<p>Un abrazo,<br><strong>Taty Contadora AI Agent</strong></p>
`;

return {
  json: {
    email_body: html,
    count: items.length
  }
};
